import React, { useEffect, useState, useContext } from 'react';
import { AuthContext } from '../contexts/AuthContext';
import { useNavigate } from 'react-router-dom';
import JoinModal from './JoinModal';

const API_URL = 'http://localhost:3001/api';

export default function Lobby() {
  const { token, user, refreshUser } = useContext(AuthContext);
  const navigate = useNavigate();
  const [rooms, setRooms] = useState([]);
  const [myContests, setMyContests] = useState([]);
  const [liveContests, setLiveContests] = useState([]);
  const [message, setMessage] = useState('');
  const [msgType, setMsgType] = useState('');
  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState('all');
  const [showCreate, setShowCreate] = useState(false);
  const [joinTarget, setJoinTarget] = useState(null);
  const [joining, setJoining] = useState(false);
  const [newRoom, setNewRoom] = useState({
    roomId: '',
    name: '',
    maxPlayers: 4,
    entryFee: 49,
    prizeDistribution: 'top4',
  });

  const fetchRooms = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/rooms`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (!res.ok) throw new Error('Unable to load rooms');
      setRooms(await res.json());
    } catch (e) {
      console.error('fetchRooms error', e);
    }
  };

  const fetchMyContests = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/rooms/my-contests`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.ok) setMyContests(await res.json());
    } catch (e) {
      console.error('fetchMyContests error', e);
    }
  };

  const fetchLiveContests = async () => {
    if (!token) return;
    try {
      const res = await fetch(`${API_URL}/rooms/live`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.ok) setLiveContests(await res.json());
    } catch (e) {
      console.error('fetchLiveContests error', e);
    }
  };

  useEffect(() => {
    fetchRooms();
    fetchMyContests();
    fetchLiveContests();
    const interval = setInterval(() => {
      fetchRooms();
      fetchMyContests();
      fetchLiveContests();
    }, 5000);
    return () => clearInterval(interval);
  }, [token]);

  const joinRoom = async () => {
    if (!joinTarget) return;
    try {
      setJoining(true);
      const res = await fetch(`${API_URL}/rooms/join`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ roomId: joinTarget._id }),
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Join failed');

      await refreshUser();
      setJoinTarget(null);
      setMessage('✓ Successfully joined!');
      setMsgType('success');
      setTimeout(() => setMessage(''), 3000);

      // Navigate to room
      navigate(`/room/${joinTarget.roomId}`);
    } catch (err) {
      setMessage(err.message || 'Join failed');
      setMsgType('error');
      setTimeout(() => setMessage(''), 5000);
    } finally {
      setJoining(false);
    }
  };

  const createRoom = async (e) => {
    e.preventDefault();
    if (!newRoom.roomId.trim()) {
      setMessage('Room ID is required');
      setMsgType('error');
      return;
    }
    try {
      setLoading(true);
      const payload = {
        roomId: newRoom.roomId.trim(),
        name: newRoom.name.trim() || `Contest #${newRoom.roomId.trim()}`,
        maxPlayers: Number(newRoom.maxPlayers),
        entryFee: Number(newRoom.entryFee),
        prizeDistribution: newRoom.prizeDistribution,
      };
      const res = await fetch(`${API_URL}/rooms/create`, {
        method: 'POST',
        headers: {
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
      if (!res.ok) {
        const data = await res.json();
        throw new Error(data.message || 'Could not create room');
      }
      setNewRoom({ roomId: '', name: '', maxPlayers: 4, entryFee: 49, prizeDistribution: 'top4' });
      setMessage('✓ Contest created!');
      setMsgType('success');
      setShowCreate(false);
      await fetchRooms();
      setTimeout(() => setMessage(''), 3000);
    } catch (e) {
      setMessage(e.message || 'Could not create room');
      setMsgType('error');
    } finally {
      setLoading(false);
    }
  };

  const tabs = [
    { key: 'all', label: 'All Contests', icon: '🏟️', count: rooms.filter((r) => r.status === 'waiting').length },
    { key: 'my', label: 'My Contests', icon: '👤', count: myContests.length },
    { key: 'live', label: 'Live', icon: '🔴', count: liveContests.length },
  ];

  const getDisplayRooms = () => {
    switch (activeTab) {
      case 'my':
        return myContests;
      case 'live':
        return liveContests;
      default:
        return rooms;
    }
  };

  const displayRooms = getDisplayRooms();

  return (
    <div className="min-h-screen bg-hero">
      <div className="max-w-7xl mx-auto px-4 py-6">
        {/* Hero Section */}
        <div className="mb-8 animate-fade-in">
          <div className="flex flex-wrap items-end justify-between gap-4 mb-2">
            <div>
              <h1 className="text-3xl sm:text-4xl font-black tracking-tight text-white mb-1">
                Contest <span className="text-gradient-gold">Lobby</span>
              </h1>
              <p className="text-slate-400 text-sm">
                Join a contest, compete, and win real prizes
              </p>
            </div>
            {/* BUG 2 FIX: Only admin can see create contest button */}
            {user?.role === 'admin' && (
              <button
                onClick={() => setShowCreate(!showCreate)}
                className="btn-primary"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
                </svg>
                Create Contest
              </button>
            )}
          </div>
        </div>

        {/* Message Alert */}
        {message && (
          <div
            className={`mb-6 p-4 rounded-xl border animate-slide-down ${
              msgType === 'success'
                ? 'bg-emerald-500/10 border-emerald-500/20 text-emerald-400'
                : 'bg-red-500/10 border-red-500/20 text-red-400'
            }`}
          >
            {message}
          </div>
        )}

        {/* Create Room Panel */}
        {showCreate && user?.role === 'admin' && (
          <div className="mb-8 card animate-slide-down">
            <div className="flex items-center justify-between mb-5">
              <h3 className="text-lg font-bold text-white">Create New Contest</h3>
              <button onClick={() => setShowCreate(false)} className="text-slate-500 hover:text-white transition-colors">
                ✕
              </button>
            </div>
            <form onSubmit={createRoom} className="grid sm:grid-cols-2 lg:grid-cols-5 gap-4">
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1.5">Room ID *</label>
                <input
                  value={newRoom.roomId}
                  onChange={(e) => setNewRoom((prev) => ({ ...prev, roomId: e.target.value }))}
                  placeholder="e.g. blitz-01"
                  className="input-field"
                  required
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1.5">Contest Name</label>
                <input
                  value={newRoom.name}
                  onChange={(e) => setNewRoom((prev) => ({ ...prev, name: e.target.value }))}
                  placeholder="e.g. Blitz Battle"
                  className="input-field"
                />
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1.5">Max Players</label>
                <select
                  value={newRoom.maxPlayers}
                  onChange={(e) => setNewRoom((prev) => ({ ...prev, maxPlayers: e.target.value }))}
                  className="select-field"
                >
                  <option value={2}>2 Players</option>
                  <option value={4}>4 Players</option>
                  <option value={8}>8 Players</option>
                  <option value={10}>10 Players</option>
                </select>
              </div>
              <div>
                <label className="block text-xs font-medium text-slate-400 mb-1.5">Entry Fee (₹)</label>
                <input
                  type="number"
                  min={1}
                  value={newRoom.entryFee}
                  onChange={(e) => setNewRoom((prev) => ({ ...prev, entryFee: e.target.value }))}
                  className="input-field"
                  required
                />
              </div>
              <div className="flex flex-col">
                <label className="block text-xs font-medium text-slate-400 mb-1.5">Prize Type</label>
                <div className="flex gap-2 flex-1 items-end">
                  <select
                    value={newRoom.prizeDistribution}
                    onChange={(e) => setNewRoom((prev) => ({ ...prev, prizeDistribution: e.target.value }))}
                    className="select-field flex-1"
                  >
                    <option value="top4">Top 4</option>
                    <option value="winnerTA">Winner Takes All</option>
                  </select>
                  <button type="submit" disabled={loading} className="btn-primary btn-sm whitespace-nowrap">
                    {loading ? '...' : 'Create'}
                  </button>
                </div>
              </div>
            </form>
          </div>
        )}

        {/* Tabs */}
        <div className="flex gap-1 bg-navy-800/50 backdrop-blur-sm rounded-xl p-1 mb-6 overflow-x-auto">
          {tabs.map((tab) => (
            <button
              key={tab.key}
              onClick={() => setActiveTab(tab.key)}
              className={`flex items-center gap-2 px-4 py-2.5 rounded-lg text-sm font-medium whitespace-nowrap transition-all ${
                activeTab === tab.key
                  ? 'bg-gradient-to-r from-gold-500/15 to-gold-600/10 text-gold-400 shadow-sm border border-gold-500/10'
                  : 'text-slate-400 hover:text-white hover:bg-white/5'
              }`}
            >
              <span>{tab.icon}</span>
              {tab.label}
              {tab.count > 0 && (
                <span
                  className={`px-1.5 py-0.5 rounded-full text-[10px] font-bold ${
                    activeTab === tab.key
                      ? 'bg-gold-500/20 text-gold-400'
                      : 'bg-navy-700 text-slate-500'
                  }`}
                >
                  {tab.count}
                </span>
              )}
            </button>
          ))}
        </div>

        {/* Contest Grid */}
        {displayRooms.length === 0 ? (
          <div className="card text-center py-16 animate-fade-in">
            <div className="text-5xl mb-4">
              {activeTab === 'my' ? '📭' : activeTab === 'live' ? '⏳' : '🏗️'}
            </div>
            <p className="text-slate-400 font-medium">
              {activeTab === 'my'
                ? "You haven't joined any contests yet"
                : activeTab === 'live'
                ? 'No live contests right now'
                : 'No contests available'}
            </p>
            <p className="text-slate-500 text-sm mt-1">
              {activeTab === 'all' && user?.role === 'admin' ? 'Create one to get started!' : 'Check back later!'}
            </p>
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-4">
            {displayRooms.map((r, idx) => (
              <ContestCard
                key={r.roomId}
                room={r}
                user={user}
                onJoin={() => setJoinTarget(r)}
                onEnter={() => navigate(`/room/${r.roomId}`)}
                delay={idx * 50}
              />
            ))}
          </div>
        )}
      </div>

      {/* Join Modal */}
      {joinTarget && (
        <JoinModal
          room={joinTarget}
          onConfirm={joinRoom}
          onClose={() => setJoinTarget(null)}
          loading={joining}
        />
      )}
    </div>
  );
}

function ContestCard({ room, user, onJoin, onEnter, delay }) {
  const prizePool = room.entryFee * room.maxPlayers;
  const fillPercent = (room.players.length / room.maxPlayers) * 100;
  const hasJoined = room.players.some(
    (p) => (p._id || p).toString() === user?.id?.toString()
  );
  const isWaiting = room.status === 'waiting';
  const isOngoing = room.status === 'ongoing';
  const isCompleted = room.status === 'completed';
  const isFull = room.players.length >= room.maxPlayers;

  return (
    <div
      className="contest-card animate-slide-up"
      style={{ animationDelay: `${delay}ms` }}
    >
      {/* Header row */}
      <div className="flex items-start justify-between mb-4">
        <div>
          <h3 className="text-sm font-bold text-white mb-0.5">
            {room.name || room.roomId}
          </h3>
          <p className="text-xs text-slate-500">{room.roomId}</p>
        </div>
        <div>
          {isWaiting && !isFull && <span className="badge-green">Open</span>}
          {isWaiting && isFull && <span className="badge bg-orange-500/15 text-orange-400 border border-orange-500/20">Full</span>}
          {isOngoing && (
            <span className="badge-gold">
              <span className="w-1.5 h-1.5 rounded-full bg-gold-400 animate-pulse" />
              Live
            </span>
          )}
          {isCompleted && <span className="badge bg-slate-700/50 text-slate-400 border-slate-600/30">Ended</span>}
        </div>
      </div>

      {/* Prize Pool */}
      <div className="mb-4 p-3 rounded-xl bg-navy-900/50 border border-navy-700/20">
        <div className="flex items-center justify-between">
          <div>
            <p className="text-[10px] font-medium text-slate-500 uppercase tracking-wider">Prize Pool</p>
            <p className="text-2xl font-black text-white">₹{prizePool.toLocaleString()}</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] font-medium text-slate-500 uppercase tracking-wider">Entry</p>
            <p className="text-lg font-bold text-gold-400">₹{room.entryFee}</p>
          </div>
        </div>
      </div>

      {/* Prize type + players */}
      <div className="flex items-center justify-between mb-3">
        <span
          className={`badge ${
            room.prizeDistribution === 'winnerTA' ? 'badge-gold' : 'badge-blue'
          }`}
        >
          {room.prizeDistribution === 'winnerTA' ? '🏆 Winner Takes All' : '🎯 Top 4'}
        </span>
        <span className="text-xs font-medium text-slate-400">
          {room.players.length}/{room.maxPlayers} joined
        </span>
      </div>

      {/* Slots progress bar */}
      <div className="mb-4">
        <div className="progress-bar">
          <div
            className={`progress-fill ${
              fillPercent >= 100
                ? 'bg-orange-500' 
                : fillPercent >= 80
                ? 'bg-gradient-to-r from-red-500 to-orange-500'
                : fillPercent >= 50
                ? 'bg-gradient-to-r from-gold-500 to-orange-400'
                : 'bg-gradient-to-r from-emerald-500 to-emerald-400'
            }`}
            style={{ width: `${fillPercent}%` }}
          />
        </div>
        {fillPercent >= 80 && isWaiting && !isFull && (
          <p className="text-[10px] text-red-400 mt-1">
            ⚡ Filling fast! {room.maxPlayers - room.players.length} spot{room.maxPlayers - room.players.length > 1 ? 's' : ''} left
          </p>
        )}
      </div>

      {/* Action button */}
      {isWaiting && !hasJoined && !isFull && (
        <button onClick={onJoin} className="btn-primary w-full">
          Join Now — ₹{room.entryFee}
        </button>
      )}
      {isWaiting && !hasJoined && isFull && (
        <button disabled className="btn-secondary w-full opacity-50 cursor-not-allowed">
          Contest Full
        </button>
      )}
      {hasJoined && isWaiting && (
        <button onClick={onEnter} className="btn-secondary w-full">
          ✓ Joined — Enter Room
        </button>
      )}
      {(isOngoing || isCompleted) && hasJoined && (
        <button onClick={onEnter} className="btn-primary w-full">
          {isOngoing ? '⚡ Enter Match' : '📊 View Results'}
        </button>
      )}
      {(isOngoing || isCompleted) && !hasJoined && (
        <button onClick={onEnter} className="btn-ghost w-full border border-navy-700/50">
          👁️ Spectate
        </button>
      )}
    </div>
  );
}
